script:
frappe.ui.form.on('department_grc', {
	 onload: function(frm) {
    frappe.call({
      method: "frappe.client.get_list",
      args: {
        doctype: "customer_grc",
        fields: ["name_company"]
      },
      callback: function(r) {
        if (r.message) {
          let options = r.message.map(row => row.name_company);
          frm.set_df_property("entreprise", "options", ["", ...options]);
        }
      }
    });
  }
})

frappe.ui.form.on('service_grc', {
  onload: function(frm) {
    // Charger dynamiquement les entreprises dans le champ company
    frappe.call({
      method: "frappe.client.get_list",
      args: {
        doctype: "customer_grc",
        fields: ["name_company"]
      },
      callback: function(r) {
        if (r.message) {
          let options = r.message.map(row => row.name_company);
          frm.set_df_property("company", "options", ["", ...options]);
        }
      }
    });
  },

  company: function(frm) {
    const selected_company = frm.doc.company;

    if (!selected_company) return;

    // Charger les départements liés à l'entreprise sélectionnée
    frappe.call({
      method: "frappe.client.get_list",
      args: {
        doctype: "department_grc",
        fields: ["nom_du_département"],
        filters: {
          entreprise: selected_company
        }
      },
      callback: function(r) {
        if (r.message) {
          let options = r.message.map(row => row.nom_du_département);
          frm.set_df_property("name_department", "options", ["", ...options]);
        }
      }
    });
  }
});

